+        "sqliteCode",
+        &JsValue::from_f64(f64::from(error.exit_code())),
+    );
+    let _ = set_property(
+        &object,
+        "extendedCode",
+        &JsValue::from_f64(f64::from(error.extended_error_code())),
+    );
+    let _ = set_property(&object, "message", &JsValue::from_str(&error.to_string()));
+    let _ = set_property(
